using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 200000, StartDate = DateTime.Parse("2007-09-01") }
            };
            context.Departments.AddRange(departments);

            var instructors = new[]
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") },
                new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01") }
            };
            context.Instructors.AddRange(instructors);

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 3 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2 },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 }
            };
            context.Courses.AddRange(courses);

            var students = new[]
            {
                new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
                new Student { ID = 4, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") }
            };
            context.Students.AddRange(students);

            var enrollments = new[]
            {
                new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 1, CourseID = 4022, Grade = Grade.C },
                new Enrollment { EnrollmentID = 3, StudentID = 2, CourseID = 4041, Grade = Grade.B },
                new Enrollment { EnrollmentID = 4, StudentID = 3, CourseID = 1050 }
            };
            context.Enrollments.AddRange(enrollments);

            var officeAssignments = new[]
            {
                new OfficeAssignment { InstructorID = 1, Location = "Smith 17" },
                new OfficeAssignment { InstructorID = 2, Location = "Gowan 27" }
            };
            context.OfficeAssignments.AddRange(officeAssignments);

            var courseAssignments = new[]
            {
                new CourseAssignment { CourseID = 1050, InstructorID = 1 },
                new CourseAssignment { CourseID = 4022, InstructorID = 2 },
                new CourseAssignment { CourseID = 4041, InstructorID = 3 }
            };
            context.CourseAssignments.AddRange(courseAssignments);

            context.SaveChanges();
        }
    }
}

