using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new StudentsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void Index_WithSearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_WithNameDescSort_ReturnsSortedDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.True(model.Count > 1);
            Assert.True(string.Compare(model[0].LastName, model[1].LastName) > 0);
        }

        [Fact]
        public void Index_WithDateSort_ReturnsSortedByDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.True(model.Count > 1);
            Assert.True(model[0].EnrollmentDate <= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_WithDateDescSort_ReturnsSortedByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.True(model.Count > 1);
            Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_DefaultSort_ReturnsSortedByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.True(model.Count > 1);
            Assert.True(string.Compare(model[0].LastName, model[1].LastName) <= 0);
        }

        [Fact]
        public void Index_SearchStringResetsPage()
        {
            var result = _controller.Index(null, "oldFilter", "newSearch", 3) as ViewResult;

            Assert.NotNull(result);
            // When searchString is not null, page should be reset to 1
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            var result = _controller.Index("Date", null, "test", null) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToNameDesc()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Details_IncludesEnrollments()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.NotNull(student.Enrollments);
            Assert.True(student.Enrollments.Count > 0);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithStudentModel()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_AddsStudentToDatabase()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "NewStudent",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            _controller.Create(student);

            Assert.Contains(_context.Students, s => s.LastName == "NewStudent");
        }

        [Fact]
        public void Create_Post_InvalidDate_MinValue_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidDate_TooEarly_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(1, student.ID);
        }

        [Fact]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First(s => s.ID == 1);
            student.LastName = "UpdatedName";

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidModel_UpdatesStudent()
        {
            var student = _context.Students.AsNoTracking().First(s => s.ID == 1);
            student.LastName = "UpdatedLastName";

            _controller.Edit(student);

            var updated = _context.Students.AsNoTracking().First(s => s.ID == 1);
            Assert.Equal("UpdatedLastName", updated.LastName);
        }

        [Fact]
        public void Edit_Post_InvalidDate_MinValue_ReturnsView()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(1, student.ID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Students.Find(1));
        }

        #endregion
    }
}

