using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/tmp/wwwroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/tmp");
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithListOfCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void Index_IncludesDepartmentData()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(course.Department);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithEmptyCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidModel_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_NoImage_AddsCourseToDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Another New Course",
                Credits = 3,
                DepartmentID = 2
            };

            _controller.Create(course, null);

            Assert.Contains(_context.Courses, c => c.CourseID == 8888);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 7777, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 6666, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.exe");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 5555, Title = "Test", Credits = 3, DepartmentID = 1 };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.jpg");
            mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal(1050, course.CourseID);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_ValidModel_NoImage_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidModel_UpdatesCourse()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Advanced Chemistry";

            _controller.Edit(course, null);

            var updated = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            Assert.Equal("Advanced Chemistry", updated.Title);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.txt");
            mockFile.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.png");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal(1050, course.CourseID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        #endregion
    }
}

