using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / Student / Instructor Tests

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_Required()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        [Fact]
        public void Student_LastName_Required()
        {
            var student = new Student
            {
                LastName = null,
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_Required()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = null,
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastName_MaxLength50()
        {
            var student = new Student
            {
                LastName = new string('a', 51),
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_MaxLength50()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = new string('a', 51),
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Instructor_HireDate_Required()
        {
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(instructor);
            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_FullName_Works()
        {
            var instructor = new Instructor { LastName = "Doe", FirstMidName = "Jane" };

            Assert.Equal("Doe, Jane", instructor.FullName);
        }

        #endregion

        #region Course Tests

        [Fact]
        public void Course_Credits_Range0To5()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_ValidRange()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Test",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        [Fact]
        public void Course_Title_MinLength3()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Title_MaxLength50()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('a', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        #endregion

        #region Department Tests

        [Fact]
        public void Department_Name_MinLength3()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_ValidModel_PassesValidation()
        {
            var dept = new Department
            {
                Name = "English",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(dept);
            Assert.Empty(results);
        }

        #endregion

        #region Enrollment Tests

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            var results = ValidateModel(enrollment);
            Assert.Empty(results);
        }

        [Fact]
        public void Enrollment_Grade_HasAllValues()
        {
            Assert.Equal(5, Enum.GetValues(typeof(Grade)).Length);
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(4, (int)Grade.F);
        }

        #endregion

        #region ErrorViewModel Tests

        [Fact]
        public void ErrorViewModel_ShowRequestId_True_WhenRequestIdNotEmpty()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };

            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_False_WhenRequestIdNull()
        {
            var model = new ErrorViewModel { RequestId = null };

            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_False_WhenRequestIdEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };

            Assert.False(model.ShowRequestId);
        }

        #endregion

        #region Notification Model Tests

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Test message", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasCorrectValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region OfficeAssignment Tests

        [Fact]
        public void OfficeAssignment_Location_MaxLength50()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('a', 51)
            };

            var results = ValidateModel(office);
            Assert.Contains(results, r => r.MemberNames.Contains("Location"));
        }

        [Fact]
        public void OfficeAssignment_ValidLocation_PassesValidation()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            var results = ValidateModel(office);
            Assert.Empty(results);
        }

        #endregion

        #region CourseAssignment Tests

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }

        #endregion

        #region SchoolViewModels Tests

        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new SchoolViewModels.AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2023-01-01"),
                StudentCount = 5
            };

            Assert.Equal(DateTime.Parse("2023-01-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var data = new SchoolViewModels.InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        #endregion

        private static IList<ValidationResult> ValidateModel(object model)
        {
            var context = new ValidationContext(model);
            var results = new List<ValidationResult>();
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }
    }
}

