using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void DbSets_AreAccessible()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.Notifications);
            Assert.NotNull(_context.People);
        }

        [Fact]
        public void Students_CanBeQueried()
        {
            var students = _context.Students.ToList();
            Assert.Equal(4, students.Count);
        }

        [Fact]
        public void Courses_CanBeQueried()
        {
            var courses = _context.Courses.ToList();
            Assert.Equal(4, courses.Count);
        }

        [Fact]
        public void Departments_CanBeQueried()
        {
            var departments = _context.Departments.ToList();
            Assert.Equal(3, departments.Count);
        }

        [Fact]
        public void Instructors_CanBeQueried()
        {
            var instructors = _context.Instructors.ToList();
            Assert.Equal(3, instructors.Count);
        }

        [Fact]
        public void Enrollments_CanBeQueried()
        {
            var enrollments = _context.Enrollments.ToList();
            Assert.Equal(4, enrollments.Count);
        }

        [Fact]
        public void CourseAssignments_CanBeQueried()
        {
            var assignments = _context.CourseAssignments.ToList();
            Assert.Equal(3, assignments.Count);
        }

        [Fact]
        public void OfficeAssignments_CanBeQueried()
        {
            var offices = _context.OfficeAssignments.ToList();
            Assert.Equal(2, offices.Count);
        }

        [Fact]
        public void Student_Enrollment_Relationship_Works()
        {
            var student = _context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == 1);

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Course_Department_Relationship_Works()
        {
            var course = _context.Courses
                .Include(c => c.Department)
                .First(c => c.CourseID == 1050);

            Assert.NotNull(course.Department);
            Assert.Equal("Engineering", course.Department.Name);
        }

        [Fact]
        public void Instructor_OfficeAssignment_Relationship_Works()
        {
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == 1);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Instructor_CourseAssignment_Relationship_Works()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.ID == 1);

            Assert.Single(instructor.CourseAssignments);
        }

        [Fact]
        public void CanAdd_And_Retrieve_Student()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Student");
            Assert.Equal("New", retrieved.FirstMidName);
        }

        [Fact]
        public void CanDelete_Student()
        {
            var student = _context.Students.First(s => s.ID == 4);
            _context.Students.Remove(student);
            _context.SaveChanges();

            Assert.Null(_context.Students.Find(4));
            Assert.Equal(3, _context.Students.Count());
        }

        [Fact]
        public void CanUpdate_Student()
        {
            var student = _context.Students.First(s => s.ID == 1);
            student.LastName = "ModifiedName";
            _context.SaveChanges();

            var updated = _context.Students.First(s => s.ID == 1);
            Assert.Equal("ModifiedName", updated.LastName);
        }
    }
}

