[Fact]
public void Edit_Post_ValidModel_RedirectsToIndex()
{
    // Detach tracked entity to avoid tracking conflict
    var tracked = _context.Students.Local.FirstOrDefault(s => s.ID == 1);
    if (tracked != null) _context.Entry(tracked).State = EntityState.Detached;

    var student = new Student { ID = 1, FirstMidName = "Carson", LastName = "UpdatedName", EnrollmentDate = DateTime.Parse("2010-09-01") };

    var result = _controller.Edit(student) as RedirectToActionResult;

    Assert.NotNull(result);
    Assert.Equal("Index", result.ActionName);
}

[Fact]
public void Edit_Post_ValidModel_UpdatesStudent()
{
    var tracked = _context.Students.Local.FirstOrDefault(s => s.ID == 1);
    if (tracked != null) _context.Entry(tracked).State = EntityState.Detached;

    var student = new Student { ID = 1, FirstMidName = "Carson", LastName = "UpdatedLastName", EnrollmentDate = DateTime.Parse("2010-09-01") };

    _controller.Edit(student);

    var updated = _context.Students.AsNoTracking().First(s => s.ID == 1);
    Assert.Equal("UpdatedLastName", updated.LastName);
}

